css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #fafafa; color: #1a1a1a; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; border-bottom: 1px solid #eee; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #999; text-decoration: none; font-size: 14px; font-weight: 600; }
.cart-icon { font-size: 15px; font-weight: 700; }
.product-page { display: grid; grid-template-columns: 1fr 1fr; gap: 50px; padding: 50px 60px; }
.main-img { aspect-ratio: 1; background: linear-gradient(150deg, #f0f0f5, #e8e8f0); border-radius: 24px; display: flex; align-items: center; justify-content: center; font-size: 120px; margin-bottom: 16px; }
.thumb-row { display: flex; gap: 12px; }
.thumb { width: 64px; height: 64px; background: #f0f0f5; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 24px; cursor: pointer; border: 2px solid transparent; }
.thumb.active { border-color: #6366f1; }
.brand-tag { color: #6366f1; font-size: 12px; font-weight: 800; letter-spacing: 0.1em; }
.info h1 { font-size: 32px; font-weight: 800; margin: 10px 0 12px; }
.rating { font-size: 14px; margin-bottom: 18px; }
.rating span { color: #999; font-size: 13px; font-weight: 600; }
.price-row { display: flex; align-items: baseline; gap: 12px; margin-bottom: 20px; flex-wrap: wrap; }
.price { font-size: 32px; font-weight: 800; }
.old-price { font-size: 18px; color: #bbb; text-decoration: line-through; }
.discount { background: #fee2e2; color: #dc2626; font-size: 12px; font-weight: 800; padding: 4px 10px; border-radius: 999px; }
.desc { color: #777; font-size: 14.5px; line-height: 1.8; margin-bottom: 26px; }
.option-group { margin-bottom: 22px; }
.option-label { display: block; font-size: 13px; font-weight: 700; color: #999; margin-bottom: 10px; text-transform: uppercase; letter-spacing: 0.04em; }
.color-options { display: flex; gap: 10px; align-items: center; margin-bottom: 8px; }
.color-dot { width: 32px; height: 32px; border-radius: 50%; cursor: pointer; border: 3px solid transparent; }
.color-dot.active { border-color: #6366f1; }
.selected-label { font-size: 13px; color: #999; font-weight: 600; }
.qty-row { display: flex; align-items: center; gap: 16px; }
.qty-row button { width: 36px; height: 36px; border-radius: 8px; background: #f0f0f5; border: none; font-size: 18px; font-weight: 700; cursor: pointer; }
.qty-row span { font-size: 16px; font-weight: 700; min-width: 24px; text-align: center; }
.actions { display: flex; gap: 12px; margin-bottom: 28px; }
.btn-primary { flex: 1; background: #6366f1; color: white; border: none; padding: 16px; border-radius: 12px; font-size: 14.5px; font-weight: 700; cursor: pointer; }
.btn-secondary { flex: 1; background: #1a1a1a; color: white; border: none; padding: 16px; border-radius: 12px; font-size: 14.5px; font-weight: 700; cursor: pointer; }
.features { display: flex; flex-direction: column; gap: 10px; }
.feature { font-size: 13.5px; color: #777; }
.reviews { padding: 0 60px 60px; }
.reviews h2 { font-size: 24px; font-weight: 800; margin-bottom: 20px; }
.review-list { display: flex; flex-direction: column; gap: 16px; max-width: 700px; }
.review { background: white; border: 1px solid #eee; border-radius: 14px; padding: 18px 20px; }
.review-head { display: flex; justify-content: space-between; margin-bottom: 8px; }
.review p { color: #777; font-size: 13.5px; line-height: 1.7; }
@media (max-width: 900px) { .navbar, .product-page, .reviews { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .product-page { grid-template-columns: 1fr; gap: 24px; } .main-img { font-size: 80px; } }

js:
let qty = 1;
let selectedColor = 'Siyah';
let cartCount = 0;

function setMain(el, emoji) {
  document.getElementById('mainImg').textContent = emoji;
  document.querySelectorAll('.thumb').forEach(t => t.classList.remove('active'));
  el.classList.add('active');
}

function selectColor(el, color) {
  document.querySelectorAll('.color-dot').forEach(d => d.classList.remove('active'));
  el.classList.add('active');
  selectedColor = color;
  document.getElementById('colorLabel').textContent = color;
}

function changeQty(delta) {
  qty = Math.max(1, qty + delta);
  document.getElementById('qtyLabel').textContent = qty;
}

function addToCart() {
  cartCount += qty;
  document.getElementById('cartCount').textContent = cartCount;
  alert(`${qty} adet "Aurora Akıllı Saat" (${selectedColor}) sepete eklendi!`);
}

function buyNow() {
  alert(`Satın alma sayfasına yönlendiriliyorsunuz: ${qty} adet Aurora Akıllı Saat (${selectedColor})`);
}
